### 6. chart/templates/deployment.yaml
The Kubernetes Deployment manifest.

```yaml
apiVersion: apps/v1
kind: Deployment
metadata:
  name: {{ include "nginx-web-server.fullname" . }}
  labels:
    {{- include "nginx-web-server.labels" . | nindent 4 }}
spec:
  replicas: {{ .Values.replicaCount }}
  selector:
    matchLabels:
      {{- include "nginx-web-server.selectorLabels" . | nindent 6 }}
  template:
    metadata:
      labels:
        {{- include "nginx-web-server.selectorLabels" . | nindent 8 }}
    spec:
      containers:
        - name: {{ .Chart.Name }}
          image: "{{ .Values.image.repository }}:{{ .Values.image.tag }}"
          imagePullPolicy: {{ .Values.image.pullPolicy }}
          ports:
            - name: http
              containerPort: 80
              protocol: TCP
          resources:
            {{- toYaml .Values.resources | nindent 12 }}
```

### 7. chart/templates/service.yaml
The Kubernetes Service manifest.

```yaml
apiVersion: v1
kind: Service
metadata:
  name: {{ include "nginx-web-server.fullname" . }}
  labels:
    {{- include "nginx-web-server.labels" . | nindent 4 }}
spec:
  type: {{ .Values.service.type }}
  ports:
    - port: {{ .Values.service.port }}
      targetPort: http
      protocol: TCP
      name: http
  selector:
    {{- include "nginx-web-server.selectorLabels" . | nindent 4 }}
```

### 8. chart/templates/_helpers.tpl
(Standard Helm helpers, usually needed for the templates above to render correctly)

```yaml
{{/*
Expand the name of the chart.
*/}}
{{- define "nginx-web-server.name" -}}
{{- default .Chart.Name .Values.nameOverride | trunc 63 | trimSuffix "-" }}
{{- end }}

{{/*
Create a default fully qualified app name.
We truncate at 63 chars because some Kubernetes name fields are limited to this (by the DNS naming spec).
If release name contains chart name it will be used as a full name.
*/}}
{{- define "nginx-web-server.fullname" -}}
{{- if .Values.fullnameOverride }}
{{- .Values.fullnameOverride | trunc 63 | trimSuffix "-" }}
{{- else }}
{{- $name := default .Chart.Name .Values.nameOverride }}
{{- if contains $name .Release.Name }}
{{- .Release.Name | trunc 63 | trimSuffix "-" }}
{{- else }}
{{- printf "%s-%s" .Release.Name $name | trunc 63 | trimSuffix "-" }}
{{- end }}
{{- end }}
{{- end }}

{{/*
Create chart name and version as used by the chart label.
*/}}
{{- define "nginx-web-server.chart" -}}
{{- printf "%s-%s" .Chart.Name .Chart.Version | replace "+" "_" | trunc 63 | trimSuffix "-" }}
{{- end }}

{{/*
Common labels
*/}}
{{- define "nginx-web-server.labels" -}}
helm.sh/chart: {{ include "nginx-web-server.chart" . }}
{{ include "nginx-web-server.selectorLabels" . }}
{{- if .Chart.AppVersion }}
app.kubernetes.io/version: {{ .Chart.AppVersion | quote }}
{{- end }}
app.kubernetes.io/managed-by: {{ .Release.Service }}
{{- end }}

{{/*
Selector labels
*/}}
{{- define "nginx-web-server.selectorLabels" -}}
app.kubernetes.io/name: {{ include "nginx-web-server.name" . }}
app.kubernetes.io/instance: {{ .Release.Name }}
{{- end }}
```

Do you want me to apply the `compositiondefinition.yaml` to your cluster? 
**Important:** It contains a placeholder URL (`oci://ghcr.io/yourusername/yourrepo/nginx-web-server`). If you apply it as-is, the Krateo operator will try to fetch the chart from that URL and fail until you actually push the chart there.

